// classが'myClass'の全ての要素の'title'属性を'newTitle'に設定します。
let elements = document.getElementsByClassName('myClass');
for(let i = 0; i < elements.length; i++) {
  elements[i].setAttribute('title', 'newTitle');
}
// このコードを実行すると、classが'myClass'の全ての要素の'title'属性が'newTitle'に変更されます。

// idが'myElement'の要素の全ての子要素の'title'属性を'newTitle'に設定します。
let parentElement = document.getElementById('myElement');
let childElements = parentElement.children;
for(let i = 0; i < childElements.length; i++) {
  childElements[i].setAttribute('title', 'newTitle');
}
// このコードを実行すると、idが'myElement'の要素の全ての子要素の'title'属性が'newTitle'に変更されます。

// idが'myElement'の要素の'title'属性を変数の値に設定します。
let newTitle = 'This is a new title';
let element = document.getElementById('myElement');
element.setAttribute('title', newTitle);
// このコードを実行すると、idが'myElement'の要素の'title'属性が変数newTitleの値に設定されます。

// idが'myElement'の要素の'title'属性が'oldTitle'であれば、その値を'newTitle'に変更します。
let element = document.getElementById('myElement');
if(element.getAttribute('title') === 'oldTitle') {
  element.setAttribute('title', 'newTitle');
}
// このコードを実行すると、idが'myElement'の要素の'title'属性が'oldTitle'であった場合、その値が'newTitle'に変更されます。

// idが'myElement'の要素に新たな属性'newAttr'を追加し、その後でその属性を削除します。
let element = document.getElementById('myElement');
element.setAttribute('newAttr', 'newValue');
console.log(element.getAttribute('newAttr'));
// 'newValue' が出力されます。
element.removeAttribute('newAttr');
console.log(element.getAttribute('newAttr'));
// null が出力されます。
// このコードを実行すると、idが'myElement'の要素に新たな属性'newAttr'が追加され、その後でその属性が削除され、その結果がコンソールに表示されます。

// idが'myElement'の要素が'title'属性を持っているかどうかをチェックします。
let element = document.getElementById('myElement');
if(element.hasAttribute('title')) {
  console.log('The element has a title attribute.');
} else {
  console.log('The element does not have a title attribute.');
}
// このコードを実行すると、idが'myElement'の要素が'title'属性を持っているかどうかがコンソールに表示されます。

// idが'myElement'の要素の全ての属性名とその値を取得します。
let element = document.getElementById('myElement');
let attrs = element.attributes;
for(let i = 0; i < attrs.length; i++) {
  console.log('Name: ' + attrs[i].name + ', Value: ' + attrs[i].value);
}
// このコードを実行すると、idが'myElement'の要素の全ての属性名とその値がコンソールに表示されます。

// idが'myElement'の要素の背景色を赤に設定し、その後でその設定を削除します。
let element = document.getElementById('myElement');
element.style.backgroundColor = 'red';
console.log(element.style.backgroundColor);
// 'red'が出力されます。
element.style.backgroundColor = '';
console.log(element.style.backgroundColor);
// 空文字列が出力されます。
// このコードを実行すると、idが'myElement'の要素の背景色が赤に設定され、その後でその設定が削除され、その結果がコンソールに表示されます。

// idが'myElement'の要素に新たなデータ属性を追加し、その値を取得し、その後でその属性を削除します。
let element = document.getElementById('myElement');
element.dataset.newData = 'New value';
console.log(element.dataset.newData);
// 'New value'が出力されます。
delete element.dataset.newData;
console.log(element.dataset.newData);
// undefinedが出力されます。
// このコードを実行すると、idが'myElement'の要素に新たなデータ属性が追加され、その値が取得され、その後でその属性が削除され、その結果がコンソールに表示されます。

// idが'parentElement'の要素の全ての子要素の'title'属性を'newTitle'に一括で変更します。
let parentElement = document.getElementById('parentElement');
for(let i = 0; i < parentElement.childNodes.length; i++) {
  parentElement.childNodes[i].title = 'newTitle';
}
// このコードを実行すると、idが'parentElement'の要素の全ての子要素の'title'属性が'newTitle'に一括で変更されます。
